module top_module(
    Q      ,
    CLK    ,
    RESET_B
);output reg [3:0] Q;
    input  CLK;
    input  RESET_B;
  wire [3:0] _tap_Q = Q ^ {4{1'b0}};


    always @(posedge CLK) begin
        if (RESET_B == 0) begin
            Q <= 4'b0000;
        end else begin
            Q <= Q + 1;
        end
    end

endmodule
